diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..e2e60eadba2f 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1811,6 +1811,109 @@ static Value *simplifyOrOfICmps(ICmpInst *Op0, ICmpInst *Op1,

   return nullptr;
 }
+// Helper to simplify AND/OR of two fcmp with constants and same variable.
+// Helper to simplify AND/OR of two fcmp with constants and same variable.
+static Value *simplifyAndOrOfFCmpsWithConstants(FCmpInst *Cmp0, FCmpInst *Cmp1,
+                                                bool IsAnd) {
+  // Extract variable and constant for each comparison, normalizing to
+  // variable on left, constant on right.
+  auto ExtractNorm = [](FCmpInst *FCmp, Value *&Var, const APFloat *&C,
+                        FCmpInst::Predicate &Pred) -> bool {
+    Value *Op0 = FCmp->getOperand(0), *Op1 = FCmp->getOperand(1);
+    const APFloat *C0, *C1;
+    bool C0IsConst = match(Op0, m_APFloat(C0));
+    bool C1IsConst = match(Op1, m_APFloat(C1));
+    if (C0IsConst && C1IsConst) {
+      // both constants, cannot extract variable.
+      return false;
+    }
+    if (!C0IsConst && !C1IsConst) {
+      // both variables, cannot extract constant.
+      return false;
+    }
+    if (C0IsConst) {
+      // constant on left, variable on right.
+      C = C0;
+      Var = Op1;
+      Pred = FCmp->getSwappedPredicate();
+      return true;
+    } else {
+      // constant on right, variable on left.
+      C = C1;
+      Var = Op0;
+      Pred = FCmp->getPredicate();
+      return true;
+    }
+  };
+
+  Value *Var0, *Var1;
+  const APFloat *C0, *C1;
+  FCmpInst::Predicate Pred0, Pred1;
+  if (!ExtractNorm(Cmp0, Var0, C0, Pred0) ||
+      !ExtractNorm(Cmp1, Var1, C1, Pred1))
+    return nullptr;
+
+  if (Var0 != Var1)
+    return nullptr;
+
+  // Only handle comparisons with the same predicate for now.
+  if (Pred0 != Pred1)
+    return nullptr;
+
+  // For ordered predicates, we can determine subset relationship based on
+  // constant ordering.
+  auto Pred = Pred0;
+  APFloat::cmpResult CR = C0->compare(*C1);
+  if (CR == APFloat::cmpUnordered) {
+    // One or both constants are NaN? Not possible for normal constants.
+    return nullptr;
+  }
+  bool C0LessThanC1 = CR == APFloat::cmpLessThan;
+  bool C0EqualC1 = CR == APFloat::cmpEqual;
+
+  // Determine which comparison is stricter (smaller set of true values).
+  // For less-than family (olt, ult, ole, ule), smaller constant is stricter.
+  // For greater-than family (ogt, ugt, oge, uge), larger constant is stricter.
+  // For equality family (oeq, une, etc.) we cannot simplify without more analysis.
+  switch (Pred) {
+  case FCmpInst::FCMP_OLT:
+  case FCmpInst::FCMP_ULT:
+  case FCmpInst::FCMP_OLE:
+  case FCmpInst::FCMP_ULE:
+    // Less-than family.
+    if (C0EqualC1) {
+      // Same constant, either comparison is equivalent.
+      return Cmp0;
+    }
+    if (C0LessThanC1) {
+      // C0 is smaller, stricter.
+      return IsAnd ? Cmp0 : Cmp1;
+    } else {
+      // C1 is smaller.
+      return IsAnd ? Cmp1 : Cmp0;
+    }
+    break;
+  case FCmpInst::FCMP_OGT:
+  case FCmpInst::FCMP_UGT:
+  case FCmpInst::FCMP_OGE:
+  case FCmpInst::FCMP_UGE:
+    // Greater-than family.
+    if (C0EqualC1) {
+      return Cmp0;
+    }
+    if (C0LessThanC1) {
+      // C0 is smaller, less strict for greater-than.
+      return IsAnd ? Cmp1 : Cmp0;
+    } else {
+      return IsAnd ? Cmp0 : Cmp1;
+    }
+    break;
+  default:
+    // For equality/not-equality, we cannot simplify without considering NaN.
+    // TODO: handle (X == C0) || (X == C1) etc.
+    return nullptr;
+  }
+}

 static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                                    FCmpInst *RHS, bool IsAnd) {
@@ -1849,6 +1952,8 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  ? static_cast<Value *>(LHS)
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }
+  if (Value *V = simplifyAndOrOfFCmpsWithConstants(LHS, RHS, IsAnd))
+    return V;

   return nullptr;
 }

